{"content":"/**
 * Holo Golf VR — Trajectory Preview
 * Shows a dotted arc path predicting ball trajectory while aiming.
 * Updates in real-time as aim direction and power change.
 * Accounts for wind, gravity wells, and ice friction.
 */
import {
  World,
  Group,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Color,
  AdditiveBlending,
  Vector3,
} from "@iwsdk/core";
import { BallController } from "./ball";
import { PutterController } from "./putter";
import { CourseManager } from "./course";

const TRAJECTORY_DOTS = 24;
const TRAJECTORY_STEP = 0.03; // simulation timestep
const TRAJECTORY_STEPS = 60; // total simulation steps
const DOT_SPACING = Math.floor(TRAJECTORY_STEPS / TRAJECTORY_DOTS);
const BALL_FRICTION = 0.985;
const BALL_DAMPING = 0.02;
const DOT_RADIUS = 0.012;

export class TrajectoryPreview {
  private world: World;
  private ball: BallController;
  private putter: PutterController;
  private courseManager: CourseManager;
  private dotsGroup: Group;
  private dots: Mesh[] = [];
  private visible = false;
  private courseIndex = 0;

  // Colors for trajectory fade
  private nearColor = new Color(0x44ffff);
  private farColor = new Color(0x0044ff);

  constructor(
    world: World,
    ball: BallController,
    putter: PutterController,
    courseManager: CourseManager,
  ) {
    this.world = world;
    this.ball = ball;
    this.putter = putter;
    this.courseManager = courseManager;
    this.dotsGroup = new Group();
    world.scene.add(this.dotsGroup);

    // Create dot meshes
    const geo = new SphereGeometry(DOT_RADIUS, 4, 4);
    for (let i = 0; i < TRAJECTORY_DOTS; i++) {
      const t = i / (TRAJECTORY_DOTS - 1);
      const color = new Color().lerpColors(this.nearColor, this.farColor, t);
      const mat = new MeshBasicMaterial({
        color,
        transparent: true,
        opacity: 0.6 * (1 - t * 0.7),
        blending: AdditiveBlending,
      });
      const dot = new Mesh(geo, mat);
      dot.visible = false;
      this.dots.push(dot);
      this.dotsGroup.add(dot);
    }
  }

  setCourseIndex(idx: number) {
    this.courseIndex = idx;
  }

  setCourseThemeColors(primary: number, secondary: number) {
    this.nearColor.setHex(primary);
    this.farColor.setHex(secondary);
    // Update dot materials
    for (let i = 0; i < this.dots.length; i++) {
      const t = i / (TRAJECTORY_DOTS - 1);
      const mat = this.dots[i].material as MeshBasicMaterial;
      mat.color.lerpColors(this.nearColor, this.farColor, t);
    }
  }

  show() {
    this.visible = true;
    for (const dot of this.dots) dot.visible = true;
  }

  hide() {
    this.visible = false;
    for (const dot of this.dots) dot.visible = false;
  }

  update(dt: number) {
    if (!this.visible) return;
    if (!this.putter.isAiming || this.putter.aimPower < 0.05) {
      for (const dot of this.dots) dot.visible = false;
      return;
    }

    // Simulate trajectory
    const startPos = this.ball.position.clone();
    const dir = this.putter.aimDirection.clone().normalize();
    const power = this.putter.aimPower;
    const velocity = dir.multiplyScalar(power);

    const pos = startPos.clone();
    const vel = velocity.clone();
    let dotIdx = 0;

    // Get current wind/zone info (simplified — we check start and a few intermediate positions)
    for (let step = 0; step < TRAJECTORY_STEPS && dotIdx < TRAJECTORY_DOTS; step++) {
      // Apply physics
      vel.y -= 9.8 * TRAJECTORY_STEP; // gravity
      vel.x *= BALL_FRICTION;
      vel.z *= BALL_FRICTION;

      // Check wind at this position
      const windResult = this.courseManager.getWindAtPosition(pos);
      if (windResult && windResult.force > 0) {
        vel.add(windResult.direction.clone().multiplyScalar(windResult.force * TRAJECTORY_STEP * 0.5));
      }

      pos.add(vel.clone().multiplyScalar(TRAJECTORY_STEP));

      // Clamp to ground
      if (pos.y < 0) {
        pos.y = 0;
        vel.y = Math.abs(vel.y) * 0.2; // small bounce
      }

      // Place dot at intervals
      if (step % DOT_SPACING === 0) {
        this.dots[dotIdx].position.copy(pos);
        this.dots[dotIdx].position.y += 0.01; // slight lift above surface
        this.dots[dotIdx].visible = true;

        // Scale dots: smaller as they get further
        const scale = 1.0 - (dotIdx / TRAJECTORY_DOTS) * 0.5;
        this.dots[dotIdx].scale.setScalar(scale);

        dotIdx++;
      }

      // Stop if ball is basically stopped
      if (vel.length() < 0.01 && pos.y < 0.01) break;
    }

    // Hide remaining dots
    for (let i = dotIdx; i < TRAJECTORY_DOTS; i++) {
      this.dots[i].visible = false;
    }
  }

  dispose() {
    this.world.scene.remove(this.dotsGroup);
  }
}
